class Solution {
    public int[] twoSum(int[] numbers, int target) {
        //front and end points
        int left = 0;
        int right = numbers.length - 1;
        boolean found = false;
        while (!found) {
            int sum = numbers[left] + numbers[right];
            if (sum == target) {
                return new int[] {left+1, right+1};
            } else if (sum < target) {
                //sum is less so increase left
                left++;
            } else {
                //sum is greater so decrease right
                right--;
            }
        }
        return new int[2];
    }
}

