public class Solution {
    public int[] productExceptSelf(int[] nums) {
        int zeros = 0;
        int prod = 1;
        int length = nums.length;
        //count nums
        for (int num : nums) {
            if (num != 0) {
                prod *= num;
            } else {
                zeros++;
            }
        }
        //if we have 2 or more zeros then the list is empty
        if (zeros >= 2) {
            return new int[length];
        }
        //go through nums and fill ans array
        int[] ans = new int[length];
        for (int i = 0; i < length; i++) {
            if (zeros == 1) {
                ans[i] = (nums[i] == 0) ? prod : 0;
            } else {
                ans[i] = prod / nums[i];
            }
        }
        return ans;
    }
}
